import os
import numpy as np
from typing import List, Dict, Any
import json
import pickle
from pathlib import Path


class SimpleVectorDB:
    def __init__(self, embedding_dim: int = 384):
        self.embedding_dim = embedding_dim
        self.documents = []
        self.embeddings = []
        self.metadata = []
    
    def add_documents(self, docs: List[str], embeddings: np.ndarray, metadata: List[Dict] = None):
        self.documents.extend(docs)
        self.embeddings.extend(embeddings)
        if metadata:
            self.metadata.extend(metadata)
        else:
            self.metadata.extend([{}] * len(docs))
    
    def search(self, query_embedding: np.ndarray, top_k: int = 5) -> List[Dict]:
        if len(self.embeddings) == 0:
            return []
        
        embeddings_array = np.array(self.embeddings)
        similarities = np.dot(embeddings_array, query_embedding) / (
            np.linalg.norm(embeddings_array, axis=1) * np.linalg.norm(query_embedding)
        )
        
        top_indices = np.argsort(similarities)[-top_k:][::-1]
        
        results = []
        for idx in top_indices:
            results.append({
                'document': self.documents[idx],
                'score': float(similarities[idx]),
                'metadata': self.metadata[idx]
            })
        
        return results
    
    def save(self, filepath: str):
        data = {
            'documents': self.documents,
            'embeddings': self.embeddings,
            'metadata': self.metadata,
            'embedding_dim': self.embedding_dim
        }
        with open(filepath, 'wb') as f:
            pickle.dump(data, f)
    
    def load(self, filepath: str):
        with open(filepath, 'rb') as f:
            data = pickle.load(f)
        self.documents = data['documents']
        self.embeddings = data['embeddings']
        self.metadata = data['metadata']
        self.embedding_dim = data['embedding_dim']


class SimpleEmbedding:
    def __init__(self, embedding_dim: int = 384):
        self.embedding_dim = embedding_dim
        np.random.seed(42)
        self.vocab = {}
        self.vocab_counter = 0
    
    def _get_word_vector(self, word: str) -> np.ndarray:
        if word not in self.vocab:
            self.vocab[word] = np.random.randn(self.embedding_dim)
        return self.vocab[word]
    
    def embed(self, text: str) -> np.ndarray:
        words = text.lower().split()
        if not words:
            return np.zeros(self.embedding_dim)
        
        word_vectors = [self._get_word_vector(word) for word in words]
        embedding = np.mean(word_vectors, axis=0)
        embedding = embedding / (np.linalg.norm(embedding) + 1e-8)
        return embedding
    
    def embed_batch(self, texts: List[str]) -> np.ndarray:
        return np.array([self.embed(text) for text in texts])


class DocumentLoader:
    @staticmethod
    def load_from_directory(directory: str) -> List[Dict[str, Any]]:
        documents = []
        directory_path = Path(directory)
        
        if not directory_path.exists():
            return documents
        
        for file_path in directory_path.rglob('*'):
            if file_path.is_file():
                try:
                    if file_path.suffix in ['.txt', '.md']:
                        with open(file_path, 'r', encoding='utf-8') as f:
                            content = f.read()
                            documents.append({
                                'content': content,
                                'source': str(file_path),
                                'filename': file_path.name
                            })
                    elif file_path.suffix == '.json':
                        with open(file_path, 'r', encoding='utf-8') as f:
                            data = json.load(f)
                            if isinstance(data, list):
                                for item in data:
                                    if isinstance(item, dict) and 'content' in item:
                                        documents.append(item)
                                    elif isinstance(item, str):
                                        documents.append({
                                            'content': item,
                                            'source': str(file_path),
                                            'filename': file_path.name
                                        })
                            elif isinstance(data, dict) and 'content' in data:
                                documents.append(data)
                except Exception as e:
                    print(f"Error loading {file_path}: {e}")
        
        return documents
    
    @staticmethod
    def chunk_text(text: str, chunk_size: int = 500, overlap: int = 50) -> List[str]:
        words = text.split()
        chunks = []
        
        for i in range(0, len(words), chunk_size - overlap):
            chunk = ' '.join(words[i:i + chunk_size])
            if chunk:
                chunks.append(chunk)
            
            if i + chunk_size >= len(words):
                break
        
        return chunks if chunks else [text]


class LLMClient:
    def __init__(self):
        pass
    
    def generate(self, prompt: str, max_tokens: int = 500) -> str:
        return f"[SIMULATED RESPONSE] Based on the provided context, here's the answer to your query. This is a simulated response. In production, this would call an actual LLM API (OpenAI, Anthropic, etc.) with the prompt containing the retrieved documents."


class RAGSystem:
    def __init__(self, embedding_dim: int = 384, chunk_size: int = 500, chunk_overlap: int = 50):
        self.vector_db = SimpleVectorDB(embedding_dim=embedding_dim)
        self.embedder = SimpleEmbedding(embedding_dim=embedding_dim)
        self.llm_client = LLMClient()
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap
    
    def load_documents(self, directory: str):
        print(f"Loading documents from {directory}...")
        documents = DocumentLoader.load_from_directory(directory)
        
        if not documents:
            print("No documents found!")
            return
        
        print(f"Loaded {len(documents)} documents")
        
        all_chunks = []
        all_metadata = []
        
        for doc in documents:
            content = doc.get('content', '')
            chunks = DocumentLoader.chunk_text(content, self.chunk_size, self.chunk_overlap)
            
            for i, chunk in enumerate(chunks):
                all_chunks.append(chunk)
                all_metadata.append({
                    'source': doc.get('source', 'unknown'),
                    'filename': doc.get('filename', 'unknown'),
                    'chunk_index': i,
                    'total_chunks': len(chunks)
                })
        
        print(f"Created {len(all_chunks)} chunks")
        print("Generating embeddings...")
        
        embeddings = self.embedder.embed_batch(all_chunks)
        
        self.vector_db.add_documents(all_chunks, embeddings, all_metadata)
        print("Documents loaded and indexed successfully!")
    
    def query(self, user_query: str, top_k: int = 5, include_sources: bool = True) -> Dict[str, Any]:
        print(f"\nProcessing query: {user_query}")
        
        query_embedding = self.embedder.embed(user_query)
        
        retrieved_docs = self.vector_db.search(query_embedding, top_k=top_k)
        
        if not retrieved_docs:
            return {
                'answer': 'No relevant documents found in the knowledge base.',
                'sources': [],
                'retrieved_documents': []
            }
        
        context = self._build_context(retrieved_docs)
        
        prompt = self._create_prompt(user_query, context, retrieved_docs)
        
        answer = self.llm_client.generate(prompt)
        
        sources = []
        if include_sources:
            sources = self._extract_sources(retrieved_docs)
        
        return {
            'answer': answer,
            'sources': sources,
            'retrieved_documents': retrieved_docs,
            'prompt': prompt
        }
    
    def _build_context(self, retrieved_docs: List[Dict]) -> str:
        context_parts = []
        for i, doc in enumerate(retrieved_docs, 1):
            context_parts.append(f"Document {i} (Score: {doc['score']:.3f}):")
            context_parts.append(f"Source: {doc['metadata'].get('filename', 'unknown')}")
            context_parts.append(f"Content: {doc['document']}")
            context_parts.append("")
        
        return "\n".join(context_parts)
    
    def _create_prompt(self, query: str, context: str, retrieved_docs: List[Dict]) -> str:
        prompt = f"""You are a helpful assistant that answers questions based on the company's internal knowledge base.

Use the following retrieved documents to answer the user's question. If the answer cannot be found in the documents, say so.

RETRIEVED DOCUMENTS:
{context}

USER QUESTION: {query}

Please provide a comprehensive answer based on the above documents. If you reference specific information, indicate which document it came from.

ANSWER:"""
        
        return prompt
    
    def _extract_sources(self, retrieved_docs: List[Dict]) -> List[Dict]:
        sources = []
        seen = set()
        
        for doc in retrieved_docs:
            source_key = (doc['metadata'].get('filename'), doc['metadata'].get('source'))
            if source_key not in seen:
                seen.add(source_key)
                sources.append({
                    'filename': doc['metadata'].get('filename', 'unknown'),
                    'source': doc['metadata'].get('source', 'unknown'),
                    'score': doc['score']
                })
        
        return sources
    
    def save_index(self, filepath: str):
        self.vector_db.save(filepath)
        print(f"Index saved to {filepath}")
    
    def load_index(self, filepath: str):
        self.vector_db.load(filepath)
        print(f"Index loaded from {filepath}")


